// ---------- 1. Pull fields from related Health Check items ----------
var Scores       = @[All of Health Score with nulls](inn_274796984_274796983);
var Risks        = @[All of Drop-off Risk % with nulls](inn_274796985_274796983);
var Upgrades     = @[All of Upgrade Likelihood % with nulls](inn_274796986_274796983);
var Archetypes   = @[All of Archetype with nulls](inn_274796987_274796983);
var RunDates     = @[All of Health Check Date with nulls](inn_274797013_274796983);
var Summaries    = @[All of Explanatory Summary with nulls](inn_274796990_274796983);
var Links        = @[All of ltti [H] with nulls](inn_274797014_274796983);

// ---------- Helpers ----------
function toStr(v){ return (v === null || v === undefined) ? "" : String(v); }
function isValidDate(d){ return d instanceof Date && !isNaN(d.getTime()); }

function riskIcon(r){
  var n = parseInt(r, 10);
  if (isNaN(n)) return "⚪";     // unknown
  if (n <= 30)  return "_";    // low
  if (n <= 60)  return "_";    // medium
  return "_";                  // high
}

// ----- SCORE EMOJI -----
function scoreIcon(s){
  var n = parseInt(s, 10);
  if (isNaN(n)) return "";
  if (n <= 40)  return "_ ";
  if (n <= 60)  return "_ ";
  if (n <= 80)  return "_ ";
  return "_ ";
}

// ----- UPGRADE EMOJI -----
function upgradeIcon(s){
  var n = parseInt(s, 10);
  if (isNaN(n)) return "";
  if (n <= 30)  return "_ ";
  if (n <= 60)  return "↗️ ";
  if (n <= 80)  return "_ ";
  return "_ ";
}

// ----- ARCHETYPE EMOJI -----
function archetypeIcon(a){
  if (!a) return "";
  a = a.toLowerCase();

  if (a.indexOf("loyal") !== -1) return "_ ";
  if (a.indexOf("explorer") !== -1) return "_ ";
  if (a.indexOf("power") !== -1) return "⚡ ";
  if (a.indexOf("risk") !== -1) return "⚠️ ";
  if (a.indexOf("dormant") !== -1) return "_ ";
  if (a.indexOf("billing") !== -1 || a.indexOf("issue") !== -1) return "_ ";
  if (a.indexOf("expansion") !== -1) return "_ ";
  if (a.indexOf("feedback") !== -1) return "_️ ";

  return "";
}


// ---------- 2. Combine ----------
var combined = [];
var maxLen = Math.max(
  Scores.length, Risks.length, Upgrades.length,
  Archetypes.length, RunDates.length, Summaries.length, Links.length
);

for (var i = 0; i < maxLen; i++) {
  var rawDate = RunDates[i] || null;
  var safeDate = rawDate ? new Date(rawDate) : null;

  combined.push({
    score: toStr(Scores[i]).trim(),
    risk: toStr(Risks[i]).trim(),
    upgrade: toStr(Upgrades[i]).trim(),
    archetype: toStr(Archetypes[i]).trim(),
    summary: toStr(Summaries[i]).trim(),
    link: toStr(Links[i]).trim(),
    date: isValidDate(safeDate) ? safeDate : null
  });
}

// ---------- 3. Sort by Run Date DESC ----------
combined.sort(function(a, b){
  if (!a.date && !b.date) return 0;
  if (!a.date) return 1;
  if (!b.date) return -1;
  return b.date - a.date;
});

// ---------- 4. Build Markdown Table ----------
var md  = "| Date | Score | Δ Score | Risk | Upgrade % | Archetype | Notes | Check |\n";
md     += "| ---- | ----- | ------- | ---- | ---------- | --------- | ----- | ----- |\n";

for (var i = 0; i < combined.length; i++) {
  var item = combined[i];

  if (!item.score && !item.risk && !item.upgrade && !item.archetype && !item.summary && !item.date && !item.link) {
    continue;
  }

  var dateCell     = item.date ? moment(item.date).format("MM/DD/YY") : "—";
  var scoreCell    = item.score ? scoreIcon(item.score) + item.score : "—";

  // ----- Δ Score vs NEXT row (one below) -----
  var deltaCell = "—";
  var currScore = parseInt(item.score, 10);

  if (!isNaN(currScore) && (i + 1) < combined.length) {
    var nextScore = parseInt(combined[i + 1].score, 10);
    if (!isNaN(nextScore)) {
      var diff = currScore - nextScore;   // current (more recent) vs previous (older)
      if (diff > 0)      { deltaCell = "+" + diff; }
      else if (diff < 0) { deltaCell = String(diff); }
      else               { deltaCell = "0"; }
    }
  }

  // ----- Risk with icon (unchanged from before) -----
  var riskCell = "—";
  if (item.risk) {
    riskCell = riskIcon(item.risk) + " " + item.risk;
  }

  var upgradeCell = item.upgrade ? upgradeIcon(item.upgrade) + item.upgrade : "—";

  var archetypeCell = item.archetype ? archetypeIcon(item.archetype) + item.archetype : "—";


  var summaryText = item.summary
    ? (item.summary.length > 30 ? item.summary.substr(0, 30) + "..." : item.summary)
    : "—";

  var linkCell = "—";
  if (item.link) {
    linkCell = "[_ View](" + item.link + ")";
  }

  md += "| " + dateCell +
        " | " + scoreCell +
        " | " + deltaCell +
        " | " + riskCell +
        " | " + upgradeCell +
        " | " + archetypeCell +
        " | " + summaryText +
        " | " + linkCell +
        " |\n";
}

// ---------- 5. Output ----------
md;

