var show = @[Nanacast Transactions | Show Most Recent](field_204029025) || 10;
var rowsJson = @[All of Order Row [H]](in_274590249_129807977); // from Order app

// Parse safely
var rows = [];
for (var i=0;i<rowsJson.length;i++){
  try {
    var r = JSON.parse(rowsJson[i]);
    if (r && r.dateISO) rows.push(r);
  } catch(e){}
}

// Sort DESC (most-recent first)
rows.sort(function(a,b){
  return new Date(b.dateISO||0) - new Date(a.dateISO||0);
});

// Limit
if (show != "All") {
  var n = parseInt(show,10);
  if (isNaN(n) || n <= 0) n = 10;
  rows = rows.slice(0,n);
}

// Helpers
function esc(s){ return (s||"").replace(/\|/g,"\\|"); }
function trunc(s,n){ s=s||""; return s.length>55 ? s.substring(0,55)+"…" : s; }
function money(n){ n=(isNaN(n)?0:Number(n)); return "$"+n.toFixed(2); }
function dFmt(iso){ return iso ? moment(iso).format("MM-DD-YYYY") : ""; }

// Platform → emoji
function platIcon(p){
  if (p=="Nanacast")   return "_";
  if (p=="Circle")     return "⭕";
  if (p=="Thrivecart") return "_";
  return "_";
}

// Build table
if (rows.length === 0) {
  "No transactions found.";
} else {
  var out = "Date | Description | Price | Platform | Event \n";
  out += "---|---|---|---|--- \n";

  for (var i=0;i<rows.length;i++){
    var r = rows[i] || {};
    var d = dFmt(r.dateISO);
    var dLink = r.link ? "["+d+"]("+r.link+")" : d;
    out += dLink+" | "+esc(trunc(r.description,55))+" | "+money(r.price)+" | "+
           platIcon(r.platform)+" "+esc(r.platform||"")+" | "+esc(r.eventType||"")+"\n";
  }

  out;
}

