// --- Collect arrays from related Progress Tracker items ---
var titles          = @[All of Title](in_125311850_125306242);
var types           = @[All of Progress Tracker Type](in_128205285_125306242);
var overallStatus   = @[All of Overall Status](in_149529784_125306242);
var dateEnrolled    = @[All of Date Enrolled](in_126215935_125306242);
var lastTouch       = @[All of Last Touch](in_127701942_125306242);
var ticklerDate     = @[All of Last Touch Tickler](in_128248653_125306242);
var ticklerOverride = @[All of Last Touch Tickler Delay Override](in_168892307_125306242);
var touchStatus     = @[All of Last Touch Status](in_153443921_125306242);

var psDmStatus      = @[All of PS Group DM Status](in_273000530_125306242);
var psDmLink        = @[All of PS Group DM on Circle](in_273136936_125306242);

var coach           = @[All of Coach calc [H]](in_274898143_125306242);
var coachUser       = @[All of [H] Coach Podio User](in_131330288_125306242);

var autoResults     = @[All of Automate Test Results Email](in_172904004_125306242);

var ptUrl           = @[All of Item URL [H]](in_185356885_125306242);
var ptItemId        = @[All of Podio Item ID Text [H]](in_155580968_125306242);
var ptEmailAddress  = @[All of PT Email Address [H]](in_185280538_125306242);

// --- Build tracker array ---
var trackers = [];
for (var i = 0; i < titles.length; i++) {
  trackers.push({
    pt_id: ptItemId[i] || null,
    title: titles[i] || "",
    type: types[i] || "",
    overall_status: overallStatus[i] || "",
    date_enrolled: dateEnrolled[i] || null,
    last_touch: lastTouch[i] || null,
    last_touch_tickler: ticklerDate[i] || null,
    last_touch_tickler_override: ticklerOverride[i] || "",
    last_touch_status: touchStatus[i] || "",

    ps_group_dm_status: psDmStatus[i] || "",
    ps_group_dm_link: psDmLink[i] || "",

    coach: coach[i] || "",
    coach_podio_user: coachUser[i] || "",

    automate_test_results_email: autoResults[i] || "",
    pt_item_url: ptUrl[i] || "",
    pt_email_address: ptEmailAddress[i] || ""
  });
}

// --- Sort by Date Enrolled (newest first) ---
trackers.sort(function (a, b) {
  var da = a.date_enrolled ? new Date(a.date_enrolled).getTime() : 0;
  var db = b.date_enrolled ? new Date(b.date_enrolled).getTime() : 0;
  return db - da;
});

// --- Summary fields for the health-check payload ---
var activeCount = 0;
var latest = trackers.length ? trackers[0] : null;

for (var j = 0; j < trackers.length; j++) {
  var status = (trackers[j].overall_status || "").toLowerCase();
  if (status.indexOf("active") > -1 || status.indexOf("enrolled") > -1) {
    activeCount++;
  }
}

var out = {
  progress_tracker_count: trackers.length,
  active_progress_tracker_count: activeCount,
  last_progress_type:  latest ? latest.type : null,
  last_progress_status: latest ? latest.overall_status : null,
  last_progress_touch_date: latest ? latest.last_touch : null,
  last_progress_coach: latest ? latest.coach : null,
  trackers: trackers
};

JSON.stringify(out);

// --- Collect arrays from related Help Desk Tickets ---
var ids        = @[All of HD Ticket ID [H]](in_143427125_125146452);
var subjects   = @[All of Subject](in_125145746_125146452);
var issuesRaw  = @[All of Issue](in_122333512_125146452);
var types      = @[All of Type](in_121385656_119252258);
var statuses   = @[All of Status](in_122333513_125146452);
var priorities = @[All of Priority](in_122333508_125146452);
var sources    = @[All of Source](in_125305447_125146452);
var agents     = @[All of CCO Team Member calc [H]](in_274898025_125146452);
var received   = @[All of Date Received](in_122333509_125146452);
var lastTouch  = @[All of Last Touch Point](in_134317212_125146452);

// --- Helper: strip HTML + truncate long text for the AI payload ---
function cleanIssue(html) {
  if (!html) return "";
  // remove HTML tags
  var txt = ("" + html).replace(/<[^>]+>/g, "");
  // collapse whitespace
  txt = txt.replace(/\s+/g, " ").trim();
  // limit length so the JSON doesn't explode
  if (txt.length > 500) {
    txt = txt.substr(0, 500) + "…";
  }
  return txt;
}

// --- Build ticket array ---
var tickets = [];
for (var i = 0; i < subjects.length; i++) {
  tickets.push({
    ticket_id: ids[i] || null,
    subject: subjects[i] || "",
    type: types[i] || "",
    status: statuses[i] || "",
    priority: priorities[i] || "",
    source: sources[i] || "",
    agent: agents[i] || "",
    date_received: received[i] || null,
    last_touch: lastTouch[i] || null,
    issue_summary: cleanIssue(issuesRaw[i])
  });
}

// --- Sort by Date Received (newest first) ---
tickets.sort(function (a, b) {
  var da = a.date_received ? new Date(a.date_received).getTime() : 0;
  var db = b.date_received ? new Date(b.date_received).getTime() : 0;
  return db - da;
});

// Optional: limit to last N tickets if needed
// tickets = tickets.slice(0, 20);

// --- Top-level metadata for health check ---
var lastTicket = tickets.length ? tickets[0] : null;

var out = {
  support_ticket_count: tickets.length,
  last_support_date: lastTicket ? lastTicket.date_received : null,
  last_support_status: lastTicket ? lastTicket.status : null,
  last_support_agent: lastTicket ? lastTicket.agent : null,
  tickets: tickets
};

JSON.stringify(out);
